import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
/**
 * Regression guard for the single-monitor change. These commands are
 * self-contained blocking waiters: each awaits `result.done` and handles its
 * own terminal events (return-to-agent / session-ended / confirmed /
 * cancelled). They must pass `monitor: "wait"` so that on a reused Studio
 * session they keep polling for their own event (as a read-only reader)
 * instead of fire-and-exiting - without claiming the monitor lock or being
 * blocked by a "start" monitor that is already running.
 */
const mockOpenStudioTo = vi.fn(async (_path, _opts) => ({
    sessionId: "sess-1",
    serviceUrl: "https://test.invalid",
    apiKey: "key",
    opened: true,
    abort: vi.fn(),
    done: Promise.resolve(),
}));
vi.mock("./openStudioTo.js", () => ({
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    handleStudioError: (err) => {
        throw err;
    },
}));
vi.mock("../output.js", () => ({
    emitJson: () => { },
    blockingNote: (until) => `BLOCKING: ${until}`,
    printBlockingNotice: () => { },
}));
// startDataset / openTracePlan / startTemplatePreview report a handoff analytics
// event, which resolves an install id off the filesystem - stub it out.
vi.mock("../analytics.js", () => ({ reportHandoff: () => Promise.resolve() }));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: "key" }),
    hasCredentials: () => true,
}));
const U1 = "11111111-1111-4111-8111-111111111111";
const U2 = "22222222-2222-4222-8222-222222222222";
// Each blocking command, with argv that yields a valid Studio route.
const COMMANDS = [
    {
        name: "openExperiments",
        module: "./openExperiments.js",
        runner: "runOpenExperiments",
        argv: ["node", "openExperiments.js", U1],
    },
    {
        name: "startDataset",
        module: "./startDataset.js",
        runner: "runStartDataset",
        argv: ["node", "startDataset.js", "my-fn", U1],
    },
    {
        name: "openTracePlan",
        module: "./openTracePlan.js",
        runner: "runOpenTracePlan",
        argv: ["node", "openTracePlan.js", U1],
    },
    {
        name: "openDatasetExperiments",
        module: "./openDatasetExperiments.js",
        runner: "runOpenDatasetExperiments",
        argv: ["node", "openDatasetExperiments.js", U2],
    },
    {
        name: "startTemplatePreview",
        module: "./startTemplatePreview.js",
        runner: "runStartTemplatePreview",
        argv: ["node", "startTemplatePreview.js", "my-fn"],
    },
];
let savedArgv;
beforeEach(() => {
    savedArgv = process.argv;
    vi.spyOn(process, "exit").mockImplementation((() => { }));
});
afterEach(() => {
    process.argv = savedArgv;
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
});
describe("blocking Studio commands opt into monitoring", () => {
    for (const cmd of COMMANDS) {
        it(`${cmd.name} passes monitor: "wait" so a reused session keeps polling`, async () => {
            process.argv = cmd.argv;
            const mod = (await import(cmd.module));
            await mod[cmd.runner]({});
            expect(mockOpenStudioTo).toHaveBeenCalledTimes(1);
            const opts = mockOpenStudioTo.mock.calls[0][1];
            expect(opts.monitor).toBe("wait");
        });
    }
});
